var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"레이첼! 레이첼!","JPN":"レイチェル！　レイチェル！","ENG":"Rachel! Rachel!","TWN":"瑞秋！瑞秋！"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"왜요, 원장님. 해 달라는 빨래 청소 화단에 물 주기까지 다 끝냈잖아요.","JPN":"何ですか、院長？　洗濯に掃除に花壇の水やりまで、頼まれてたのは全部やりましたよ？","ENG":"What now, headmaster? I've done the laundry, swept the floors, and even finished watering the plants like you asked me to.","TWN":"怎麼了，院長？你叫我洗衣服、打掃、澆花，我都做完啦？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"저 이제 진짜 그림 그리러 가야 되거든요? 침식체 할애비가 와도 지금은 못 막거든요?","JPN":"そろそろ本当に絵を描きに行かないとマズいんですよ！　侵食体が来たって今のアタシは止められません！","ENG":"I really gotta go do art stuff now, okay? Not even a C.O. and his uncle could stop me now.","TWN":"我要去畫畫了啦！現在就算是侵蝕體爺爺來，也阻止不了我的！"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"지금 네 낙서가 문제냐. 밖이나 좀 내다 봐 봐.","JPN":"今落書きしている場合じゃないんだ、外を見てみろ。","ENG":"Your graffiti can wait. Take a look outside.","TWN":"現在重點是畫畫嗎？你看看外面！"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"밖에 왜요? 또 갱단끼리 싸움 났어요?","JPN":"外？　またギャング同士のトラブルですか？","ENG":"Why? Is there another gang war?","TWN":"外面怎樣？又有幫派鬧事喔？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>두려워하지 마십시오, 여러분. 저희는 제프티 바이오테크에서 파견한 의료 봉사단입니다.</color>","JPN":"<color=#ffd34c>皆様、恐れることはありません。我々はジェフティ・バイオテックから派遣された医療奉仕団です。</color>","ENG":"<color=#ffd34c>Do not be afraid, everyone. We are a medical relief team dispatched from Jehuty Biotech.</color>","TWN":"<color=#ffd34c>大家請不要害怕，我們是傑夫堤生物科技派來的義診團隊。</color>"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>지금 광장에서 무상 진료를 시행하고 있습니다. 의약품도 무상으로 지급하고 있사오니…….</color>","JPN":"<color=#ffd34c>現在、広場で無料診療を行っております。医薬品も無料配布しておりますので……</color>","ENG":"<color=#ffd34c>We are currently providing free medical examinations at the plaza. We're also offering medical supplies free of charge…</color>","TWN":"<color=#ffd34c>現在正在廣場提供義診，藥物也免費提供……</color>"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"애들 옷 입히게 좀 도와 줘라. 오늘은 공짜 건강검진 받는 날이야.","JPN":"子どもたちの着替えを手伝ってくれ。今日は無料健診の日だ。","ENG":"Help me get the children dressed. We can have them get a free physical.","TWN":"替我幫孩子們穿好衣服，今天是免費體檢的日子。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"안 돼요. 오늘은 호라이즌이 처음으로 혼자 아르바이트 하는 날이라고요.","JPN":"ダメですよ。今日はホライズンが初めてアルバイトをする日なんです。","ENG":"No. Today's Horizon's first day at her new job.","TWN":"不行，今天是地平線她第一次自己打工。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"서프라이즈 선물 준비하려면 시간 없어요.","JPN":"サプライズプレゼントを用意するには時間がないんですよ。","ENG":"I don't have enough time to prepare a surprise gift for her as it is.","TWN":"我還要去準備驚喜送給她。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"그 녀석 머리에 접시 달고 다니는 것 빼면 항상 쌩쌩하더구만. 뭘 그리 야단이야.","JPN":"そんなことよりこっちの方が大事だろう！　あいつは少し変わっているけど、いつも元気じゃないか。","ENG":"She seems to be doing just fine on her own, save for those weird plates on her head. What's with all the fuss about?","TWN":"排除她頭上掛著盤子，其他我看都很正常啊，哪需要奔波這些？！"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아휴, 진짜! 그런 심보로 사니까 독신이지!","JPN":"もう！　冷たいんだから！　そんなんだからいまだに独身なんですよ！","ENG":"Ugh! No wonder you're forever alone, you old grouch!","TWN":"哀哀～真是的！原來院長都是這種想法，難怪你還是單身狗！"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"잠깐, 나 혼자서 애들 다 어떻게 챙기라고! 레이첼!","JPN":"待ってくれ、私一人では無理なんだよ！　おい、レイチェル！","ENG":"Wait! How am I supposed to take care of all the kids by myself? Rachel!","TWN":"你等等，我一個人怎麼照顧這群小孩啦！瑞秋！"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"어디 보자, 스프레이가…… 녹색 한 통, 남색 한 통……","JPN":"どれどれ、スプレーは……緑一本と、紺が一本……","ENG":"Let's see… Spray cans… I've got green, indigo…","TWN":"我看看喔，噴漆……一桶綠色，一桶藍色……"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MEMBER2_NPC_MILITIA_NULL","text":{"KOREA":"응? 레이첼 아냐?","JPN":"あれ、レイチェルじゃないか？","ENG":"Huh? Rachel?","TWN":"嗯？那不是瑞秋嗎？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"흐야악?!","JPN":"ひゃあ！？","ENG":"Eeek!","TWN":"哇啊？！"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};